sql:
SELECT dance_name
FROM dances
ORDER BY year, dance_name;

SELECT COUNT(*) AS total_advanced_dances
FROM dances
WHERE level = 'Advanced';

SELECT dance_name
FROM dances
WHERE level = 'Advanced';

SELECT dance_style_name
FROM dance_styles
WHERE popularity > 250;

external_knowledge:
- "Most in-demand dance styles" refers to the top 3 styles with the highest number of performances; 
- The popularity of a dance style is determined by the number of times it has been performed; 
- Choreographers are the individuals responsible for creating the dance routines.

sql:
SELECT choreographer_name
FROM choreographers
WHERE choreographer_id IN (SELECT choreographer_id FROM dances);

SELECT COUNT(DISTINCT dance_id) AS number_of_dances
FROM dance_competition_awards
WHERE competition_id = 0;

SELECT dance_style_name
FROM dance_styles
WHERE popularity = (SELECT MAX(popularity) FROM dance_styles);

SELECT dance_style_name, description
FROM dance_styles
ORDER BY popularity DESC;

SELECT dance_name, year
FROM dances
ORDER BY year DESC;
